/**
 * Creates a formatter using this builder. The resulting formatter can print periods in accordance with this pattern, or parse them into period objects according to the rules defined in this builder.
 * <p>
 * If both printing and parsing are requested, then the {@link org.joda.time.format.PeriodPrinter} object returned takes precedence over the {@link org.joda.time.format.PeriodParser} object.
 * If no request for one or the other operation is made, an {@link java.lang.IllegalArgumentException} will be thrown.
 *
 * @param printer If true, requests that the resulting formatter should have the ability to format period objects into strings; if false, ignores the possibility of formatting operations.
 * @param parser If true, requests that the resulting formatter should have the ability to parse string representations of period values into period objects; if false, ignores the possibility of parsing operations.
 * @return A newly constructed {@link org.joda.time.format.PeriodFormatter} instance.
 */
public PeriodFormatter toFormatter(boolean printer, boolean parser) {
    List<Object> pairs = getElementsOrderedByPosition();
    int size = pairs.size();
    if (!printer && !parser) {
        throw new IllegalStateException("No operations were requested.");
    }
    if ((size == 1 || (pairs.get(0) instanceof LiteralElement && pairs.get(1) instanceof NumberOfUnits)) && !parser) {
        // "PT1H" -> Hour
        if (!(pairs.get(0) instanceof PrefixedNumberElement)) {
            throw new IllegalArgumentException("Can't convert to units without prefixes, such as 'P', etc., when parsing ISO duration formats");
        }
        Element e = (Element) pairs.get(0);
        String unit = ((PrefixedNumberElement) e).getPrefix().name();
        long amount = ((PrefixedNumberElement) e).getValue();
        if ("second".equalsIgnoreCase(unit)) {
            unit = "seconds";
        }
        switch (unit) {
        case "days":
            return new PeriodFormatter(new CustomPrinter("%dD"), new DefaultParser("%dD"));
        case "hours":
            return new PeriodFormatter(new CustomPrinter("%dh"), new DefaultParser("%hd"));
        default:
            throw new IllegalArgumentException("Not implemented yet: " + unit);
        }
    }
    // If we reach here, the formatter includes some elements but does not cover all fields yet...
    return new PeriodFormatter(
            new CustomPrinter("P%dY%dM%dW%ddT%02dHHMMSS"),
            new DefaultParser("P%dY%dM%dW%ddTHHMMSSZ", "\\w+_(\\d+)"));
}

